     1→// ============================================================================
     2→// Value: 런타임 값 표현
     3→// ============================================================================
     4→
     5→use crate::gc_object::{GcRef, ObjectHeap, GcData};
     6→use std::fmt;
     7→
     8→/// 런타임 값
     9→#[derive(Debug, Clone, PartialEq)]
    10→pub enum Value {
    11→    /// 정수
    12→    Int(i64),
    13→
    14→    /// 불리언
    15→    Bool(bool),
    16→
    17→    /// null
    18→    Null,
    19→
    20→    /// 배열 (GC 참조)
    21→    Array(GcRef),
    22→
    23→    /// 해시맵 (GC 참조)
    24→    HashMap(GcRef),
    25→}
    26→
    27→impl Value {
    28→    /// 값이 참인지 판단
    29→    pub fn is_truthy(&self) -> bool {
    30→        match self {
    31→            Value::Bool(b) => *b,
    32→            Value::Int(0) => false,
    33→            Value::Int(_) => true,
    34→            Value::Null => false,
    35→            Value::Array(_) => true,
    36→            Value::HashMap(_) => true,
    37→        }
    38→    }
    39→
    40→    /// GC 참조 추출 (Array 또는 HashMap이면 Some)
    41→    pub fn as_gc_ref(&self) -> Option<GcRef> {
    42→        match self {
    43→            Value::Array(gc_ref) | Value::HashMap(gc_ref) => Some(*gc_ref),
    44→            _ => None,
    45→        }
    46→    }
    47→
    48→    /// 힙을 사용하여 값을 문자열로 표시 (GC 참조 역참조)
    49→    pub fn display_with_heap(&self, heap: &ObjectHeap) -> String {
    50→        match self {
    51→            Value::Int(n) => n.to_string(),
    52→            Value::Bool(b) => b.to_string(),
    53→            Value::Null => "null".to_string(),
    54→            Value::Array(gc_ref) => {
    55→                match heap.get(*gc_ref) {
    56→                    Some(obj) => {
    57→                        match &obj.data {
    58→                            GcData::Array(arr) => {
    59→                                let elements: Vec<String> = arr
    60→                                    .iter()
    61→                                    .map(|v| v.display_with_heap(heap))
    62→                                    .collect();
    63→                                format!("[{}]", elements.join(", "))
    64→                            }
    65→                            _ => "[invalid]".to_string(),
    66→                        }
    67→                    }
    68→                    None => "[dangling]".to_string(),
    69→                }
    70→            }
    71→            Value::HashMap(gc_ref) => {
    72→                match heap.get(*gc_ref) {
    73→                    Some(obj) => {
    74→                        match &obj.data {
    75→                            GcData::HashMap(map) => {
    76→                                let mut pairs: Vec<String> = map
    77→                                    .iter()
    78→                                    .map(|(k, v)| format!("{}: {}", k, v.display_with_heap(heap)))
    79→                                    .collect();
    80→                                pairs.sort(); // 일관된 출력
    81→                                format!("{{{}}}", pairs.join(", "))
    82→                            }
    83→                            _ => "{invalid}".to_string(),
    84→                        }
    85→                    }
    86→                    None => "{dangling}".to_string(),
    87→                }
    88→            }
    89→        }
    90→    }
    91→}
    92→
    93→impl fmt::Display for Value {
    94→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
    95→        match self {
    96→            Value::Int(n) => write!(f, "{}", n),
    97→            Value::Bool(b) => write!(f, "{}", b),
    98→            Value::Null => write!(f, "null"),
    99→            Value::Array(gc_ref) => write!(f, "[array:{}]", gc_ref),
   100→            Value::HashMap(gc_ref) => write!(f, "{{hash:{}}}", gc_ref),
   101→        }
   102→    }
   103→}
   104→
   105→#[cfg(test)]
   106→mod tests {
   107→    use super::*;
   108→
   109→    #[test]
   110→    fn test_is_truthy_bool() {
   111→        assert!(Value::Bool(true).is_truthy());
   112→        assert!(!Value::Bool(false).is_truthy());
   113→    }
   114→
   115→    #[test]
   116→    fn test_is_truthy_int() {
   117→        assert!(!Value::Int(0).is_truthy());
   118→        assert!(Value::Int(1).is_truthy());
   119→        assert!(Value::Int(-1).is_truthy());
   120→    }
   121→
   122→    #[test]
   123→    fn test_is_truthy_null() {
   124→        assert!(!Value::Null.is_truthy());
   125→    }
   126→
   127→    #[test]
   128→    fn test_is_truthy_array() {
   129→        // Array는 GcRef이므로 항상 참 (GC 객체 존재하면)
   130→        assert!(Value::Array(0).is_truthy());
   131→    }
   132→
   133→    #[test]
   134→    fn test_as_gc_ref() {
   135→        assert_eq!(Value::Array(42).as_gc_ref(), Some(42));
   136→        assert_eq!(Value::HashMap(99).as_gc_ref(), Some(99));
   137→        assert_eq!(Value::Int(10).as_gc_ref(), None);
   138→        assert_eq!(Value::Bool(true).as_gc_ref(), None);
   139→        assert_eq!(Value::Null.as_gc_ref(), None);
   140→    }
   141→
   142→    #[test]
   143→    fn test_display_with_heap() {
   144→        let mut heap = ObjectHeap::new();
   145→        let arr_ref = heap.alloc(GcData::Array(vec![
   146→            Value::Int(1),
   147→            Value::Int(2),
   148→            Value::Int(3),
   149→        ]));
   150→
   151→        let value = Value::Array(arr_ref);
   152→        let display = value.display_with_heap(&heap);
   153→        assert_eq!(display, "[1, 2, 3]");
   154→    }
   155→
   156→    #[test]
   157→    fn test_display_simple_values() {
   158→        assert_eq!(Value::Int(42).to_string(), "42");
   159→        assert_eq!(Value::Bool(true).to_string(), "true");
   160→        assert_eq!(Value::Null.to_string(), "null");
   161→    }
   162→
   163→    #[test]
   164→    fn test_display_with_dangling_reference() {
   165→        let heap = ObjectHeap::new();
   166→        let value = Value::Array(999); // 존재하지 않는 참조
   167→        let display = value.display_with_heap(&heap);
   168→        assert_eq!(display, "[dangling]");
   169→    }
   170→}
