     1→// ============================================================================
     2→// Compiler: AST를 바이트코드로 변환 (v15.2 - 백필링 완성)
     3→// ============================================================================
     4→
     5→use crate::ast::{Expression, Program, Statement};
     6→use crate::bytecode::Bytecode;
     7→use crate::opcode::OpCode;
     8→
     9→/// ============================================================================
    10→/// 컴파일러 - AST → 바이트코드 변환의 핵심
    11→/// ============================================================================
    12→pub struct Compiler {
    13→    bytecode: Bytecode,
    14→    pub debug_mode: bool,
    15→}
    16→
    17→impl Compiler {
    18→    /// 새로운 컴파일러 생성
    19→    pub fn new() -> Self {
    20→        Compiler {
    21→            bytecode: Bytecode::new(),
    22→            debug_mode: false,
    23→        }
    24→    }
    25→
    26→    /// 디버그 모드 활성화
    27→    pub fn with_debug(mut self, debug: bool) -> Self {
    28→        self.debug_mode = debug;
    29→        self
    30→    }
    31→
    32→    /// 프로그램 컴파일 (메인 진입점)
    33→    pub fn compile(&mut self, program: &Program) -> Result<(), String> {
    34→        for statement in &program.statements {
    35→            self.compile_statement(statement)?;
    36→        }
    37→        Ok(())
    38→    }
    39→
    40→    /// 문장 컴파일
    41→    fn compile_statement(&mut self, stmt: &Statement) -> Result<(), String> {
    42→        match stmt {
    43→            Statement::Let { name: _, value } => {
    44→                // 값을 먼저 컴파일 (변수 할당은 후위 순서로)
    45→                self.compile_expression(value)?;
    46→            }
    47→
    48→            Statement::Expression(expr) => {
    49→                self.compile_expression(expr)?;
    50→            }
    51→
    52→            Statement::Return(expr) => {
    53→                self.compile_expression(expr)?;
    54→                self.emit(OpCode::OpReturnValue);
    55→            }
    56→
    57→            Statement::Block(stmts) => {
    58→                for stmt in stmts {
    59→                    self.compile_statement(stmt)?;
    60→                }
    61→            }
    62→        }
    63→        Ok(())
    64→    }
    65→
    66→    /// ============================================================================
    67→    /// [핵심] 표현식 컴파일 - 후위 순회(Post-order)로 바이트코드 생성
    68→    /// ============================================================================
    69→    fn compile_expression(&mut self, expr: &Expression) -> Result<(), String> {
    70→        match expr {
    71→            // 정수: 상수 풀에 추가하고 OpConstant 방출
    72→            Expression::Integer(value) => {
    73→                let idx = self.bytecode.add_constant(*value);
    74→                self.emit_with_operand(OpCode::OpConstant, idx as u16);
    75→            }
    76→
    77→            // 불리언
    78→            Expression::Boolean(true) => {
    79→                self.emit(OpCode::OpTrue);
    80→            }
    81→            Expression::Boolean(false) => {
    82→                self.emit(OpCode::OpFalse);
    83→            }
    84→
    85→            // null
    86→            Expression::Null => {
    87→                self.emit(OpCode::OpNull);
    88→            }
    89→
    90→            // 전위 연산: -x, !x
    91→            Expression::Prefix(op, right) => {
    92→                // 1. 오른쪽 먼저 컴파일
    93→                self.compile_expression(right)?;
    94→                // 2. 연산자 방출
    95→                match op.as_str() {
    96→                    "-" => self.emit(OpCode::OpMinus),
    97→                    "!" => self.emit(OpCode::OpBang),
    98→                    _ => return Err(format!("Unknown prefix operator: {}", op)),
    99→                }
   100→            }
   101→
   102→            // 중위 연산: x + y, x - y 등
   103→            Expression::Infix(op, left, right) => {
   104→                // 1. 왼쪽 피연산자 컴파일 (스택에 푸시)
   105→                self.compile_expression(left)?;
   106→                // 2. 오른쪽 피연산자 컴파일 (스택에 푸시)
   107→                self.compile_expression(right)?;
   108→                // 3. 연산자 방출 (스택에서 두 값을 팝하고 결과 푸시)
   109→                match op.as_str() {
   110→                    "+" => self.emit(OpCode::OpAdd),
   111→                    "-" => self.emit(OpCode::OpSub),
   112→                    "*" => self.emit(OpCode::OpMul),
   113→                    "/" => self.emit(OpCode::OpDiv),
   114→                    "==" => self.emit(OpCode::OpEqual),
   115→                    "!=" => self.emit(OpCode::OpNotEqual),
   116→                    "<" => self.emit(OpCode::OpLessThan),
   117→                    ">=" => self.emit(OpCode::OpGreaterThanOrEqual),
   118→                    _ => return Err(format!("Unknown infix operator: {}", op)),
   119→                }
   120→            }
   121→
   122→            // if 표현식 - 백필링 완성
   123→            Expression::If {
   124→                condition,
   125→                consequence,
   126→                alternative,
   127→            } => {
   128→                // 1. 조건 컴파일
   129→                self.compile_expression(condition)?;
   130→
   131→                // 2. 점프 명령어 방출 (목적지는 아직 모름)
   132→                let jump_not_truthy_pos = self.emit_placeholder(OpCode::OpJumpNotTruthy);
   133→
   134→                // 3. consequence 블록 컴파일
   135→                for stmt in consequence {
   136→                    self.compile_statement(stmt)?;
   137→                }
   138→
   139→                // 4. else 블록 처리
   140→                if let Some(alt) = alternative {
   141→                    // else가 있으면: jump를 else 끝으로, jump_not_truthy를 else 시작으로 백필
   142→                    let jump_pos = self.emit_placeholder(OpCode::OpJump);
   143→                    self.fix_jump(jump_not_truthy_pos);
   144→                    for stmt in alt {
   145→                        self.compile_statement(stmt)?;
   146→                    }
   147→                    self.fix_jump(jump_pos);
   148→                } else {
   149→                    // else가 없으면: jump_not_truthy를 if 이후로 백필
   150→                    self.fix_jump(jump_not_truthy_pos);
   151→                }
   152→            }
   153→
   154→            // while 루프 - 후방 점프 (주소 미리 알고 있음)
   155→            Expression::While { condition, body } => {
   156→                let loop_start = self.bytecode.len() as u16;
   157→
   158→                // 1. 조건 컴파일
   159→                self.compile_expression(condition)?;
   160→
   161→                // 2. 거짓이면 루프 탈출
   162→                let jump_not_truthy_pos = self.emit_placeholder(OpCode::OpJumpNotTruthy);
   163→
   164→                // 3. 루프 본체 컴파일
   165→                for stmt in body {
   166→                    self.compile_statement(stmt)?;
   167→                }
   168→
   169→                // 4. 루프 시작으로 다시 점프 (주소 이미 알고 있음)
   170→                self.emit_with_operand(OpCode::OpJump, loop_start);
   171→
   172→                // 5. 루프 탈출 위치로 백필
   173→                self.fix_jump(jump_not_truthy_pos);
   174→            }
   175→
   176→            // 함수 호출
   177→            Expression::Call { function, arguments } => {
   178→                // 1. 함수 컴파일
   179→                self.compile_expression(function)?;
   180→
   181→                // 2. 인자들 컴파일
   182→                for arg in arguments {
   183→                    self.compile_expression(arg)?;
   184→                }
   185→
   186→                // 3. Call 명령어 (인자 개수 지정)
   187→                self.emit_with_operand(OpCode::OpCall, arguments.len() as u16);
   188→            }
   189→
   190→            // 배열
   191→            Expression::Array(elements) => {
   192→                // 1. 각 요소 컴파일
   193→                for elem in elements {
   194→                    self.compile_expression(elem)?;
   195→                }
   196→                // 2. Array 명령어 (요소 개수)
   197→                self.emit_with_operand(OpCode::OpArray, elements.len() as u16);
   198→            }
   199→
   200→            // 인덱싱
   201→            Expression::Index(left, index) => {
   202→                // 1. 왼쪽(배열/해시) 컴파일
   203→                self.compile_expression(left)?;
   204→                // 2. 인덱스 컴파일
   205→                self.compile_expression(index)?;
   206→                // 3. Index 명령어
   207→                self.emit(OpCode::OpIndex);
   208→            }
   209→
   210→            // 식별자 (추후 구현)
   211→            Expression::Identifier(_) => {
   212→                return Err("Identifiers not yet implemented".to_string());
   213→            }
   214→        }
   215→
   216→        Ok(())
   217→    }
   218→
   219→    /// 단일 바이트 명령어 방출
   220→    fn emit(&mut self, op: OpCode) {
   221→        self.bytecode.add_instruction(op.as_byte());
   222→    }
   223→
   224→    /// 피연산자(u16 = 2바이트)를 포함한 명령어 방출
   225→    fn emit_with_operand(&mut self, op: OpCode, operand: u16) {
   226→        self.emit(op);
   227→        // u16을 [high_byte, low_byte]로 분해
   228→        let high = (operand >> 8) as u8;
   229→        let low = (operand & 0xFF) as u8;
   230→        self.bytecode.add_instruction(high);
   231→        self.bytecode.add_instruction(low);
   232→    }
   233→
   234→    /// 점프 명령어를 방출하지만 목적지는 아직 모름 (나중에 수정) - 3바이트
   235→    fn emit_placeholder(&mut self, op: OpCode) -> usize {
   236→        let pos = self.bytecode.len();
   237→        self.bytecode.add_instruction(op.as_byte());      // OpJumpNotTruthy
   238→        self.bytecode.add_instruction(0x00);              // operand high byte
   239→        self.bytecode.add_instruction(0x00);              // operand low byte
   240→        pos
   241→    }
   242→
   243→    /// 이전에 방출한 점프의 목적지를 수정 (백필링)
   244→    fn change_operand(&mut self, pos: usize, operand: u16) {
   245→        let bytes = operand.to_be_bytes();
   246→        self.bytecode.instructions[pos + 1] = bytes[0];
   247→        self.bytecode.instructions[pos + 2] = bytes[1];
   248→
   249→        if self.debug_mode {
   250→            eprintln!(
   251→                "[BACKFILL] @{}: operand=0x{:04x} ({})",
   252→                pos, operand, operand
   253→            );
   254→        }
   255→    }
   256→
   257→    /// fix_jump는 change_operand에 위임
   258→    fn fix_jump(&mut self, pos: usize) {
   259→        let target = self.bytecode.len() as u16;
   260→        self.change_operand(pos, target);
   261→    }
   262→
   263→    /// 컴파일된 바이트코드 반환
   264→    pub fn bytecode(&self) -> Bytecode {
   265→        self.bytecode.clone()
   266→    }
   267→}
   268→
   269→impl Default for Compiler {
   270→    fn default() -> Self {
   271→        Self::new()
   272→    }
   273→}
   274→
   275→#[cfg(test)]
   276→mod tests {
   277→    use super::*;
   278→
   279→    #[test]
   280→    fn test_compile_integer_literal() {
   281→        let mut compiler = Compiler::new();
   282→        let program = Program::new(vec![Statement::Expression(Expression::Integer(42))]);
   283→
   284→        compiler.compile(&program).unwrap();
   285→        let bytecode = compiler.bytecode();
   286→
   287→        assert!(!bytecode.instructions.is_empty());
   288→        assert_eq!(bytecode.constants.len(), 1);
   289→        assert_eq!(bytecode.constants[0], 42);
   290→    }
   291→
   292→    #[test]
   293→    fn test_compile_boolean() {
   294→        let mut compiler = Compiler::new();
   295→        let program = Program::new(vec![
   296→            Statement::Expression(Expression::Boolean(true)),
   297→            Statement::Expression(Expression::Boolean(false)),
   298→        ]);
   299→
   300→        compiler.compile(&program).unwrap();
   301→        let bytecode = compiler.bytecode();
   302→
   303→        assert!(!bytecode.instructions.is_empty());
   304→    }
   305→
   306→    #[test]
   307→    fn test_compile_infix_expression() {
   308→        let mut compiler = Compiler::new();
   309→        let program = Program::new(vec![Statement::Expression(Expression::Infix(
   310→            "+".to_string(),
   311→            Box::new(Expression::Integer(5)),
   312→            Box::new(Expression::Integer(3)),
   313→        ))]);
   314→
   315→        compiler.compile(&program).unwrap();
   316→        let bytecode = compiler.bytecode();
   317→
   318→        // PUSH 5, PUSH 3, ADD
   319→        assert_eq!(bytecode.constants.len(), 2);
   320→        assert_eq!(bytecode.constants[0], 5);
   321→        assert_eq!(bytecode.constants[1], 3);
   322→    }
   323→
   324→    #[test]
   325→    fn test_emit_placeholder_is_3_bytes() {
   326→        let mut compiler = Compiler::new();
   327→
   328→        let program = Program::new(vec![Statement::Expression(Expression::If {
   329→            condition: Box::new(Expression::Boolean(true)),
   330→            consequence: vec![Statement::Expression(Expression::Integer(10))],
   331→            alternative: None,
   332→        })]);
   333→
   334→        compiler.compile(&program).unwrap();
   335→        let bytecode = compiler.bytecode();
   336→
   337→        // If 표현식: Boolean + JumpNotTruthy(3) + Constant(3)
   338→        // = 1 + 3 + 3 = 7
   339→        assert!(bytecode.len() >= 7);
   340→    }
   341→
   342→    #[test]
   343→    fn test_compile_while_loop() {
   344→        let mut compiler = Compiler::new();
   345→        let program = Program::new(vec![Statement::Expression(Expression::While {
   346→            condition: Box::new(Expression::Boolean(true)),
   347→            body: vec![Statement::Expression(Expression::Integer(1))],
   348→        })]);
   349→
   350→        compiler.compile(&program).unwrap();
   351→        let bytecode = compiler.bytecode();
   352→
   353→        assert!(!bytecode.instructions.is_empty());
   354→        // Boolean(1) + JumpNotTruthy(3) + Constant(3) + Jump(3) = 10
   355→        assert!(bytecode.len() >= 10);
   356→    }
   357→}
