     2→// GC Object: 가비지 컬렉션 힙 관리
     3→// ============================================================================
     4→
     5→use crate::value::Value;
     6→use std::collections::HashMap;
     7→
     8→/// GC 힙에서의 객체 참조 (인덱스)
     9→pub type GcRef = usize;
    10→
    11→/// GC 힙에 저장되는 데이터 종류
    12→#[derive(Debug, Clone)]
    13→pub enum GcData {
    14→    /// 배열
    15→    Array(Vec<Value>),
    16→
    17→    /// 해시맵
    18→    HashMap(HashMap<String, Value>),
    19→
    20→    /// 문자열
    21→    Str(String),
    22→}
    23→
    24→/// GC가 관리하는 힙 객체
    25→#[derive(Debug, Clone)]
    26→pub struct GcObject {
    27→    /// Mark 단계 플래그 (도달 가능 여부 표시)
    28→    pub is_marked: bool,
    29→
    30→    /// 실제 데이터
    31→    pub data: GcData,
    32→}
    33→
    34→impl GcObject {
    35→    /// 새로운 GC 객체 생성
    36→    pub fn new(data: GcData) -> Self {
    37→        GcObject {
    38→            is_marked: false,
    39→            data,
    40→        }
    41→    }
    42→}
    43→
    44→/// GC 실행 통계 (교육용)
    45→#[derive(Debug, Clone, Copy)]
    46→pub struct GcStats {
    47→    /// GC 실행 전 객체 수
    48→    pub objects_before: usize,
    49→
    50→    /// GC 실행 후 객체 수
    51→    pub objects_after: usize,
    52→
    53→    /// 해제된 객체 수
    54→    pub objects_freed: usize,
    55→
    56→    /// 누적 GC 실행 횟수
    57→    pub gc_count: usize,
    58→}
    59→
    60→/// Arena 패턴 힙 - 모든 GC 객체를 소유
    61→pub struct ObjectHeap {
    62→    /// 객체 슬롯 (None = 해제된 슬롯)
    63→    objects: Vec<Option<GcObject>>,
    64→
    65→    /// 적응형 GC 임계값
    66→    gc_threshold: usize,
    67→
    68→    /// GC 실행 횟수
    69→    gc_count: usize,
    70→}
    71→
    72→impl ObjectHeap {
    73→    /// 새로운 ObjectHeap 생성 (기본 임계값: 64개 객체)
    74→    pub fn new() -> Self {
    75→        ObjectHeap {
    76→            objects: Vec::new(),
    77→            gc_threshold: 64,
    78→            gc_count: 0,
    79→        }
    80→    }
    81→
    82→    /// 커스텀 임계값으로 ObjectHeap 생성
    83→    pub fn with_threshold(threshold: usize) -> Self {
    84→        ObjectHeap {
    85→            objects: Vec::new(),
    86→            gc_threshold: threshold,
    87→            gc_count: 0,
    88→        }
    89→    }
    90→
    91→    /// 객체 할당 (빈 슬롯 재사용 or 새 슬롯 추가)
    92→    pub fn alloc(&mut self, data: GcData) -> GcRef {
    93→        let obj = GcObject::new(data);
    94→
    95→        // 빈 슬롯 찾기
    96→        for (i, slot) in self.objects.iter_mut().enumerate() {
    97→            if slot.is_none() {
    98→                *slot = Some(obj);
    99→                return i;
   100→            }
   101→        }
   102→
   103→        // 빈 슬롯이 없으면 새로 추가
   104→        self.objects.push(Some(obj));
   105→        self.objects.len() - 1
   106→    }
   107→
   108→    /// 객체 불변 조회
   109→    pub fn get(&self, gc_ref: GcRef) -> Option<&GcObject> {
   110→        self.objects.get(gc_ref)?.as_ref()
   111→    }
   112→
   113→    /// 객체 가변 조회
   114→    pub fn get_mut(&mut self, gc_ref: GcRef) -> Option<&mut GcObject> {
   115→        self.objects.get_mut(gc_ref)?.as_mut()
   116→    }
   117→
   118→    /// 살아있는 객체 수 (None이 아닌 슬롯)
   119→    pub fn live_count(&self) -> usize {
   120→        self.objects.iter().filter(|slot| slot.is_some()).count()
   121→    }
   122→
   123→    /// GC 실행 필요 여부
   124→    pub fn should_collect(&self) -> bool {
   125→        self.live_count() >= self.gc_threshold
   126→    }
   127→
   128→    /// 모든 객체의 마킹 플래그 초기화
   129→    fn reset_marks(&mut self) {
   130→        for slot in self.objects.iter_mut() {
   131→            if let Some(obj) = slot {
   132→                obj.is_marked = false;
   133→            }
   134→        }
   135→    }
   136→
   137→    /// Mark 단계: 루트에서 도달 가능한 객체들을 마킹 (worklist DFS)
   138→    pub fn mark(&mut self, roots: &[Value]) {
   139→        self.reset_marks();
   140→
   141→        // 루트에서 시작하는 모든 GcRef를 worklist에 추가
   142→        let mut worklist: Vec<GcRef> = roots
   143→            .iter()
   144→            .filter_map(|v| v.as_gc_ref())
   145→            .collect();
   146→
   147→        // Worklist DFS: 스택을 사용하여 재귀 없이 순회
   148→        while let Some(gc_ref) = worklist.pop() {
   149→            // GcRef가 유효하지 않거나 슬롯이 비었으면 스킵
   150→            if gc_ref >= self.objects.len() {
   151→                continue;
   152→            }
   153→
   154→            let Some(Some(obj)) = self.objects.get_mut(gc_ref) else {
   155→                continue;
   156→            };
   157→
   158→            // 이미 마킹되면 스킵 (순환 참조 처리)
   159→            if obj.is_marked {
   160→                continue;
   161→            }
   162→
   163→            obj.is_marked = true;
   164→
   165→            // 자식 GcRef를 수집
   166→            let children: Vec<GcRef> = match &obj.data {
   167→                GcData::Array(arr) => {
   168→                    arr.iter().filter_map(|v| v.as_gc_ref()).collect()
   169→                }
   170→                GcData::HashMap(map) => {
   171→                    map.values().filter_map(|v| v.as_gc_ref()).collect()
   172→                }
   173→                GcData::Str(_) => vec![],
   174→            };
   175→
   176→            // 자식들을 worklist에 추가
   177→            worklist.extend(children);
   178→        }
   179→    }
   180→
   181→    /// Sweep 단계: 마킹되지 않은 객체들을 해제
   182→    pub fn sweep(&mut self) -> usize {
   183→        let mut freed = 0;
   184→
   185→        for slot in self.objects.iter_mut() {
   186→            match slot {
   187→                Some(obj) if !obj.is_marked => {
   188→                    *slot = None;
   189→                    freed += 1;
   190→                }
   191→                Some(obj) => {
   192→                    // 마킹 플래그 리셋 (다음 GC 준비)
   193→                    obj.is_marked = false;
   194→                }
   195→                None => {}
   196→            }
   197→        }
   198→
   199→        freed
   200→    }
   201→
   202→    /// Mark-and-Sweep GC 실행
   203→    pub fn collect_garbage(&mut self, roots: &[Value]) -> GcStats {
   204→        let objects_before = self.live_count();
   205→
   206→        // Mark 단계
   207→        self.mark(roots);
   208→
   209→        // Sweep 단계
   210→        let objects_freed = self.sweep();
   211→
   212→        let objects_after = self.live_count();
   213→        self.gc_count += 1;
   214→
   215→        GcStats {
   216→            objects_before,
   217→            objects_after,
   218→            objects_freed,
   219→            gc_count: self.gc_count,
   220→        }
   221→    }
   222→
   223→    /// 총 할당된 슬롯 수 (None 포함)
   224→    pub fn capacity(&self) -> usize {
   225→        self.objects.len()
   226→    }
   227→
   228→    /// GC 임계값 변경
   229→    pub fn set_threshold(&mut self, threshold: usize) {
   230→        self.gc_threshold = threshold;
   231→    }
   232→
   233→    /// GC 실행 횟수 조회
   234→    pub fn gc_count(&self) -> usize {
   235→        self.gc_count
   236→    }
   237→}
   238→
   239→#[cfg(test)]
   240→mod tests {
   241→    use super::*;
   242→
   243→    #[test]
   244→    fn test_alloc_and_get() {
   245→        let mut heap = ObjectHeap::new();
   246→        let arr_data = GcData::Array(vec![Value::Int(1), Value::Int(2)]);
   247→        let gc_ref = heap.alloc(arr_data);
   248→
   249→        let obj = heap.get(gc_ref);
   250→        assert!(obj.is_some());
   251→        assert!(!obj.unwrap().is_marked);
   252→    }
   253→
   254→    #[test]
   255→    fn test_alloc_reuses_freed_slot() {
   256→        let mut heap = ObjectHeap::with_threshold(100);
   257→        let ref1 = heap.alloc(GcData::Str("first".to_string()));
   258→        let ref2 = heap.alloc(GcData::Str("second".to_string()));
   259→
   260→        assert_eq!(heap.live_count(), 2);
   261→        assert_eq!(heap.capacity(), 2);
   262→
   263→        // ref1을 수동으로 "해제" (테스트용)
   264→        heap.objects[ref1] = None;
   265→        assert_eq!(heap.live_count(), 1);
   266→
   267→        // 새 할당은 ref1의 슬롯을 재사용
   268→        let ref3 = heap.alloc(GcData::Str("third".to_string()));
   269→        assert_eq!(ref3, ref1);
   270→        assert_eq!(heap.live_count(), 2);
   271→    }
