   278→        heap.alloc(GcData::Str("a".to_string()));
   279→        assert_eq!(heap.live_count(), 1);
   280→
   281→        heap.alloc(GcData::Str("b".to_string()));
   282→        assert_eq!(heap.live_count(), 2);
   283→    }
   284→
   285→    #[test]
