   290→        // 루트에 arr_ref가 있음
   291→        let roots = vec![Value::Array(arr_ref)];
   292→        heap.mark(&roots);
   293→
   294→        // arr_ref는 마킹되어야 함
   295→        assert!(heap.get(arr_ref).unwrap().is_marked);
   296→    }
