   298→    #[test]
   299→    fn test_mark_nested_array() {
   300→        let mut heap = ObjectHeap::with_threshold(100);
   301→
   302→        // inner_arr = [1, 2]
   303→        let inner_ref = heap.alloc(GcData::Array(vec![Value::Int(1), Value::Int(2)]));
   304→
   305→        // outer_arr = [inner_arr]
   306→        let outer_ref = heap.alloc(GcData::Array(vec![Value::Array(inner_ref)]));
   307→
   308→        // 루트에 outer_arr만 있음
   309→        let roots = vec![Value::Array(outer_ref)];
   310→        heap.mark(&roots);
   311→
   312→        // 둘 다 마킹되어야 함
