   317→    #[test]
   318→    fn test_sweep_unmarked_objects() {
   319→        let mut heap = ObjectHeap::with_threshold(100);
   320→        let ref1 = heap.alloc(GcData::Str("keep".to_string()));
   321→        let ref2 = heap.alloc(GcData::Str("free".to_string()));
   322→
   323→        // ref1만 마킹
