     2→// Compiler: AST를 바이트코드로 변환 (v15.2 - 백필링 완성)
     3→// ============================================================================
     4→
     5→use crate::ast::{Expression, Program, Statement};
     6→use crate::bytecode::Bytecode;
     7→use crate::opcode::OpCode;
     8→
     9→/// ============================================================================
    10→/// 컴파일러 - AST → 바이트코드 변환의 핵심
    11→/// ============================================================================
    12→pub struct Compiler {
    13→    bytecode: Bytecode,
    14→    pub debug_mode: bool,
    15→}
    16→
    17→impl Compiler {
    18→    /// 새로운 컴파일러 생성
    19→    pub fn new() -> Self {
    20→        Compiler {
    21→            bytecode: Bytecode::new(),
    22→            debug_mode: false,
    23→        }
    24→    }
    25→
    26→    /// 디버그 모드 활성화
    27→    pub fn with_debug(mut self, debug: bool) -> Self {
    28→        self.debug_mode = debug;
    29→        self
    30→    }
    31→
    32→    /// 프로그램 컴파일 (메인 진입점)
    33→    pub fn compile(&mut self, program: &Program) -> Result<(), String> {
    34→        for statement in &program.statements {
    35→            self.compile_statement(statement)?;
    36→        }
    37→        Ok(())
    38→    }
    39→
    40→    /// 문장 컴파일
    41→    fn compile_statement(&mut self, stmt: &Statement) -> Result<(), String> {
    42→        match stmt {
    43→            Statement::Let { name: _, value } => {
    44→                // 값을 먼저 컴파일 (변수 할당은 후위 순서로)
    45→                self.compile_expression(value)?;
    46→            }
    47→
    48→            Statement::Expression(expr) => {
    49→                self.compile_expression(expr)?;
    50→            }
    51→
    52→            Statement::Return(expr) => {
    53→                self.compile_expression(expr)?;
    54→                self.emit(OpCode::OpReturnValue);
    55→            }
    56→
    57→            Statement::Block(stmts) => {
    58→                for stmt in stmts {
    59→                    self.compile_statement(stmt)?;
    60→                }
    61→            }
    62→        }
    63→        Ok(())
    64→    }
    65→
    66→    /// ============================================================================
    67→    /// [핵심] 표현식 컴파일 - 후위 순회(Post-order)로 바이트코드 생성
    68→    /// ============================================================================
    69→    fn compile_expression(&mut self, expr: &Expression) -> Result<(), String> {
    70→        match expr {
    71→            // 정수: 상수 풀에 추가하고 OpConstant 방출
    72→            Expression::Integer(value) => {
    73→                let idx = self.bytecode.add_constant(*value);
    74→                self.emit_with_operand(OpCode::OpConstant, idx as u16);
    75→            }
    76→
    77→            // 불리언
    78→            Expression::Boolean(true) => {
    79→                self.emit(OpCode::OpTrue);
    80→            }

