    88→            OpCode::OpDiv,
    89→            OpCode::OpTrue,
    90→            OpCode::OpFalse,
    91→            OpCode::OpEqual,
    92→            OpCode::OpNotEqual,
    93→            OpCode::OpLessThan,
    94→            OpCode::OpGreaterThanOrEqual,
    95→            OpCode::OpBang,
    96→            OpCode::OpMinus,
    97→            OpCode::OpJump,
    98→            OpCode::OpJumpNotTruthy,
    99→            OpCode::OpNull,
   100→            OpCode::OpPop,
   101→            OpCode::OpReturnValue,
   102→            OpCode::OpReturn,
   103→            OpCode::OpGetLocal,
   104→            OpCode::OpSetLocal,
   105→            OpCode::OpArray,
   106→            OpCode::OpHash,
